package org.apache.commons.compress.compressors.bzip2;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.compressors.bzip2.steps"
)
public class CucumberTest {
}

package org.apache.commons.compress.compressors.bzip2.steps;

import io.cucumber.java.After;
import io.cucumber.java.en.And;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.compress.compressors.bzip2.BZip2CompressorInputStream;

import java.io.*;
import java.nio.ByteBuffer;
import java.nio.channels.Channels;
import java.nio.channels.ReadableByteChannel;
import java.util.Arrays;

import static org.junit.Assert.assertArrayEquals;
import static org.junit.Assert.fail;

public class StepDefs {

    private byte[] fullData;
    private byte[] truncatedData;
    private String originalText = "root:x:0:0:root:/root:/bin/bash\nbin:x:1:1:bin:/bin:\ndaemon:x:2:2:daemon:/sbin:\n" +
            "adm:x:3:4:adm:/var/adm:\nlp:x:4:7:lp:/var/spool/lpd:\nsync:x:5:0:sync:/sbin:/bin/sync\n" +
            "shutdown:x:6:0:shutdown:/sbin:/sbin/shutdown\nhalt:x:7:0:halt:/sbin:/sbin/halt\n" +
            "mail:x:8:12:mail:/var/spool/mail:\nnews:x:9:13:news:/var/spool/news:\n" +
            "uucp:x:10:14:uucp:/var/spool/uucp:\noperator:x:11:0:operator:/root:\n" +
            "games:x:12:100:games:/usr/games:\ngopher:x:13:30:gopher:/usr/lib/gopher-data:\n" +
            "ftp:x:14:50:FTP User:/var/ftp:/bin/bash\nnobody:x:65534:65534:Nobody:/home:\n" +
            "postfix:x:100:101:postfix:/var/spool/postfix:\nniemeyer:x:500:500::/home/niemeyer:/bin/bash\n" +
            "postgres:x:101:102:PostgreSQL Server:/var/lib/pgsql:/bin/bash\n" +
            "mysql:x:102:103:MySQL server:/var/lib/mysql:/bin/bash\nwww:x:103:104::/var/www:/bin/false\n";

    private ReadableByteChannel bz2Channel;
    private boolean exceptionThrownDuringValidRead = false;
    private byte[] readResult;

    @Given("a BZip2 stream containing a single compressed block of data")
    public void setupBZip2Stream() throws IOException {
        // Create the full BZip2 compressed data
        java.io.ByteArrayOutputStream out = new java.io.ByteArrayOutputStream();
        try (org.apache.commons.compress.compressors.bzip2.BZip2CompressorOutputStream bz2out =
             new org.apache.commons.compress.compressors.bzip2.BZip2CompressorOutputStream(out)) {
            bz2out.write(originalText.getBytes(), 0, originalText.getBytes().length);
        }
        fullData = out.toByteArray();
    }

    @And("the stream is truncated immediately after the block data, missing the EOS magic and CRC")
    public void truncateStream() {
        // Truncate the data by removing the last 10 bytes (6 bytes eos_magic + 4 bytes CRC)
        truncatedData = Arrays.copyOfRange(fullData, 0, fullData.length - 10);
    }

    @When("I read the expected number of uncompressed bytes from the stream")
    public void readUncompressedBytes() throws IOException {
        try {
            InputStream source = new java.io.ByteArrayInputStream(truncatedData);
            BufferedInputStream bin = new BufferedInputStream(source);
            BZip2CompressorInputStream bzin = new BZip2CompressorInputStream(bin, true);
            bz2Channel = Channels.newChannel(bzin);

            ByteBuffer buffer = ByteBuffer.allocate(originalText.length());

            // Try to read the expected number of uncompressed bytes
            int bytesRead = bz2Channel.read(buffer);

            if (bytesRead > 0) {
                readResult = Arrays.copyOf(buffer.array(), bytesRead);
            } else {
                readResult = new byte[0];
            }

        } catch (Exception e) {
            // Check if this is during the read of valid data vs. at the end
            exceptionThrownDuringValidRead = true;
        }
    }

    @Then("I should receive all the uncompressed data matching the original content")
    public void verifyUncompressedContent() {
        if (exceptionThrownDuringValidRead) {
            fail("Exception was thrown during reading valid data");
        }
        assertArrayEquals("Uncompressed data does not match original content",
                         originalText.getBytes(), readResult);
    }

    @And("the read operation should not throw an \"unexpected end of stream\" exception during the read of valid data")
    public void verifyNoUnexpectedEndOfStream() {
        if (exceptionThrownDuringValidRead) {
            fail("An exception was thrown during the reading of valid data");
        }
    }

    // Clean up resources after each scenario
    @After
    public void tearDown() throws IOException {
        if (bz2Channel != null && bz2Channel.isOpen()) {
            bz2Channel.close();
        }
    }
}

